column.value:
{
  "pageDescription": "Sample Intake & Registration",
  "subStages": [
    {"id": "1a", "name": "Shipment Reception"},
    {"id": "1b", "name": "Sample Registration"},
    {"id": "1c", "name": "Documentation Verification"},
    {"id": "1d", "name": "Barcode Generation"}
  ],
  "dataPoints": {
    "shipmentReception": {
      "deliveryReference": {"type": "text", "label": "Delivery Reference/Tracking Number", "required": true},
      "senderName": {"type": "text", "label": "Sender Name", "required": true},
      "senderOrganization": {"type": "text", "label": "Sender Organization", "required": true},
      "receptionTimestamp": {"type": "dateTime", "label": "Reception Date/Time", "required": true},
      "packagingCondition": {"type": "choice", "label": "Packaging Condition", "options": ["Intact", "Damaged"], "required": true},
      "packagingConditionNotes": {"type": "textarea", "label": "Damage Description", "conditionalOn": "packagingCondition == Damaged"},
      "packagingPhoto": {"type": "file", "label": "Packaging Photo", "accept": "image/*", "conditionalOn": "packagingCondition == Damaged"},
      "transportTemperature": {"type": "number", "label": "Transport Temperature (C)"},
      "expectedSampleCount": {"type": "number", "label": "Expected Sample Count"}
    },
    "sampleRegistration": {
      "registrationMethod": {"type": "choice", "label": "Registration Method", "options": ["Single Entry", "Manifest Import"], "required": true},
      "externalId": {"type": "text", "label": "External/Donor ID", "required": true},
      "sampleType": {"type": "reference", "label": "Sample Type", "source": "type_of_sample", "required": true},
      "projectId": {"type": "reference", "label": "Project", "source": "project", "required": true},
      "collectionDate": {"type": "date", "label": "Collection Date", "required": true},
      "collectionTime": {"type": "time", "label": "Collection Time"},
      "initialVolume": {"type": "number", "label": "Initial Volume (mL)"},
      "biosafetyLevel": {"type": "choice", "label": "Biosafety Level", "options": ["BSL-1", "BSL-2", "BSL-3", "BSL-4"], "required": true},
      "specialHandling": {"type": "textarea", "label": "Special Handling Instructions"}
    },
    "manifestImport": {
      "manifestFile": {"type": "file", "label": "Manifest CSV File", "accept": ".csv"},
      "columnMapping": {"type": "mapping", "label": "Column Mapping"}
    },
    "documentationVerification": {
      "checkSampleIdentifiers": {"type": "verification", "label": "Sample Identifiers Match Manifest", "autoVerify": true},
      "checkProjectLinkage": {"type": "verification", "label": "Project Linkage Valid", "autoVerify": true},
      "checkEthicsApproval": {"type": "verification", "label": "Ethics Approval on File", "manual": true},
      "checkConsentRecord": {"type": "verification", "label": "Informed Consent Record", "allowNA": true, "naRequiresJustification": true},
      "checkMtaDocumented": {"type": "verification", "label": "Material Transfer Agreement", "allowNA": true, "naRequiresJustification": true},
      "checkBiosafetyMatch": {"type": "verification", "label": "Biosafety Classification Matches", "manual": true},
      "checkPackagingIntegrity": {"type": "verification", "label": "Packaging Integrity Verified", "manual": true}
    },
    "barcodeGeneration": {
      "barcodeFormat": {"type": "choice", "label": "Barcode Format", "options": ["DataMatrix", "QR Code", "Code 128"], "default": "DataMatrix"},
      "labelSize": {"type": "choice", "label": "Label Size", "options": ["Small (0.5 inch)", "Medium (1 inch)", "Large (2 inch)"]},
      "printQuantity": {"type": "number", "label": "Print Quantity", "default": 1}
    }
  },
  "systemActions": ["Generate unique biorepository barcode", "Create shipment record", "Link samples to shipment", "Auto-verify documentation checks", "Set status: Registered - Pending Storage"],
  "nextPage": "Storage Assignment"
}

{
  "pageDescription": "Storage Assignment",
  "dataPoints": {
    "locationSelection": {
      "storageRoom": {"type": "reference", "label": "Storage Room", "source": "storage_room", "required": true},
      "storageDevice": {"type": "reference", "label": "Storage Device", "source": "storage_device", "required": true, "filteredBy": "storageRoom"},
      "rack": {"type": "reference", "label": "Rack", "source": "storage_rack", "filteredBy": "storageDevice"},
      "box": {"type": "reference", "label": "Box", "source": "storage_box", "filteredBy": "rack"},
      "position": {"type": "text", "label": "Position", "placeholder": "e.g., A1, B3"}
    },
    "validation": {
      "biosafetyZoneCheck": {"type": "verification", "label": "Biosafety Zone Compatible", "autoVerify": true},
      "temperatureRangeCheck": {"type": "verification", "label": "Temperature Range Suitable", "autoVerify": true}
    },
    "confirmation": {
      "barcodeScan": {"type": "barcode", "label": "Scan Barcode to Confirm", "required": true},
      "storageTimestamp": {"type": "dateTime", "label": "Storage Date/Time", "required": true},
      "assignedBy": {"type": "text", "label": "Assigned By", "required": true}
    }
  },
  "systemActions": ["Validate biosafety zone compatibility", "Check temperature range suitability", "Record storage location", "Update sample status: Stored"],
  "nextPage": "Ongoing Storage and Monitoring"
}

{
  "pageDescription": "Ongoing Storage and Monitoring",
  "dataPoints": {
    "temperatureReading": {
      "storageDevice": {"type": "reference", "label": "Storage Device", "source": "storage_device", "required": true},
      "temperature": {"type": "number", "label": "Temperature (C)", "required": true},
      "readingTimestamp": {"type": "dateTime", "label": "Reading Date/Time", "required": true},
      "entryMethod": {"type": "choice", "label": "Entry Method", "options": ["Manual", "Sensor"], "required": true},
      "recordedBy": {"type": "text", "label": "Recorded By", "required": true}
    },
    "excursionManagement": {
      "excursionType": {"type": "choice", "label": "Excursion Type", "options": ["Warning", "Critical"]},
      "acknowledgedBy": {"type": "text", "label": "Acknowledged By"},
      "acknowledgementTimestamp": {"type": "dateTime", "label": "Acknowledgement Time"},
      "correctiveAction": {"type": "textarea", "label": "Corrective Action Notes"}
    },
    "maintenanceLog": {
      "maintenanceType": {"type": "choice", "label": "Maintenance Type", "options": ["Calibration", "Repair", "Defrost Cycle", "Preventive Maintenance", "Other"]},
      "maintenanceDate": {"type": "date", "label": "Maintenance Date"},
      "performedBy": {"type": "text", "label": "Performed By"},
      "maintenanceNotes": {"type": "textarea", "label": "Maintenance Notes"},
      "nextDueDate": {"type": "date", "label": "Next Due Date"}
    }
  },
  "systemActions": ["Detect temperature excursions", "Flag overdue devices", "Generate excursion alerts", "Track maintenance schedule"],
  "nextPage": "Sample Request & Retrieval"
}

{
  "pageDescription": "Sample Request & Retrieval",
  "dataPoints": {
    "requestSubmission": {
      "sampleBarcode": {"type": "barcode", "label": "Sample Barcode", "required": true},
      "requestorName": {"type": "text", "label": "Requestor Name", "required": true},
      "requestorProject": {"type": "reference", "label": "Project", "source": "project", "required": true},
      "purpose": {"type": "textarea", "label": "Purpose of Request", "required": true},
      "quantityNeeded": {"type": "number", "label": "Quantity Needed (mL or units)", "required": true},
      "requestDate": {"type": "date", "label": "Request Date", "required": true},
      "neededByDate": {"type": "date", "label": "Needed By Date"}
    },
    "approval": {
      "approvalStatus": {"type": "choice", "label": "Approval Status", "options": ["Pending", "Approved", "Rejected"]},
      "approvedBy": {"type": "text", "label": "Approved/Rejected By"},
      "approvalDate": {"type": "date", "label": "Approval Date"},
      "approvalComments": {"type": "textarea", "label": "Approval Comments"}
    },
    "retrieval": {
      "retrievalTimestamp": {"type": "dateTime", "label": "Retrieval Date/Time"},
      "retrievedBy": {"type": "text", "label": "Retrieved By"},
      "actualQuantityRetrieved": {"type": "number", "label": "Actual Quantity Retrieved"},
      "recipientSignature": {"type": "text", "label": "Recipient Signature"},
      "chainOfCustody": {"type": "textarea", "label": "Chain of Custody Notes"}
    }
  },
  "systemActions": ["Create request record", "Notify supervisor for approval", "Generate work order", "Update sample quantity", "Update sample status: Checked Out or Partially Aliquoted"],
  "nextPage": "QC Inspection"
}

{
  "pageDescription": "QC Inspection",
  "dataPoints": {
    "inspectionSchedule": {
      "inspectionType": {"type": "choice", "label": "Inspection Type", "options": ["Scheduled", "Random", "Post-Incident", "Pre-Shipment"], "required": true},
      "inspectionDate": {"type": "date", "label": "Inspection Date", "required": true},
      "inspectedBy": {"type": "text", "label": "Inspected By", "required": true}
    },
    "sampleVerification": {
      "sampleBarcode": {"type": "barcode", "label": "Sample Barcode", "required": true},
      "locationVerified": {"type": "boolean", "label": "Sample Present at Recorded Location", "required": true},
      "containerIntegrity": {"type": "choice", "label": "Container Integrity", "options": ["Intact", "Cracked", "Leaking", "Cap Missing/Loose"], "required": true},
      "volumeCheck": {"type": "choice", "label": "Volume Status", "options": ["As Expected", "Below Expected", "Empty"]},
      "appearanceCheck": {"type": "choice", "label": "Sample Appearance", "options": ["Normal", "Hemolyzed", "Lipemic", "Turbid", "Precipitate", "Other"]},
      "labelCondition": {"type": "choice", "label": "Label Condition", "options": ["Intact", "Faded", "Damaged", "Missing"]}
    },
    "discrepancy": {
      "discrepancyFound": {"type": "boolean", "label": "Discrepancy Found"},
      "discrepancyType": {"type": "multiSelect", "label": "Discrepancy Type", "options": ["Location Mismatch", "Container Damage", "Volume Discrepancy", "Label Issue", "Quality Degradation"], "conditionalOn": "discrepancyFound == true"},
      "discrepancyNotes": {"type": "textarea", "label": "Discrepancy Notes", "conditionalOn": "discrepancyFound == true"},
      "correctiveAction": {"type": "textarea", "label": "Corrective Action Taken", "conditionalOn": "discrepancyFound == true"},
      "quarantineRequired": {"type": "boolean", "label": "Quarantine Required", "conditionalOn": "discrepancyFound == true"}
    },
    "outcome": {
      "inspectionOutcome": {"type": "choice", "label": "Inspection Outcome", "options": ["Pass", "Conditional Pass", "Fail - Quarantine", "Fail - Disposal Required"], "required": true},
      "supervisorReview": {"type": "text", "label": "Supervisor Review"},
      "supervisorReviewDate": {"type": "date", "label": "Supervisor Review Date"}
    }
  },
  "systemActions": ["Record inspection results", "Flag discrepancies", "Update sample status if quarantined", "Generate inspection report"],
  "nextPage": "Retention & Disposal"
}

{
  "pageDescription": "Retention & Disposal",
  "dataPoints": {
    "retentionReview": {
      "sampleBarcode": {"type": "barcode", "label": "Sample Barcode", "required": true},
      "retentionPolicy": {"type": "reference", "label": "Retention Policy", "source": "retention_policy"},
      "retentionExpiryDate": {"type": "date", "label": "Retention Expiry Date"},
      "extensionRequested": {"type": "boolean", "label": "Extension Requested"},
      "extensionJustification": {"type": "textarea", "label": "Extension Justification", "conditionalOn": "extensionRequested == true"},
      "newExpiryDate": {"type": "date", "label": "New Expiry Date", "conditionalOn": "extensionRequested == true"}
    },
    "disposalAuthorization": {
      "disposalReason": {"type": "choice", "label": "Disposal Reason", "options": ["Retention period expired", "Sample depleted", "Quality degradation", "Project completion", "Donor/Ethics withdrawal", "Other"], "required": true},
      "requestedBy": {"type": "text", "label": "Disposal Requested By", "required": true},
      "requestDate": {"type": "date", "label": "Request Date", "required": true},
      "firstAuthorization": {"type": "text", "label": "First Authorization (Requestor)", "required": true},
      "firstAuthDate": {"type": "date", "label": "First Authorization Date", "required": true},
      "secondAuthorization": {"type": "text", "label": "Second Authorization (Supervisor)", "required": true},
      "secondAuthDate": {"type": "date", "label": "Second Authorization Date", "required": true}
    },
    "disposalExecution": {
      "disposalMethod": {"type": "choice", "label": "Disposal Method", "options": ["Autoclaving", "Incineration", "Chemical Treatment"], "required": true},
      "disposalDate": {"type": "date", "label": "Disposal Date", "required": true},
      "disposedBy": {"type": "text", "label": "Disposed By", "required": true},
      "witnessSignature": {"type": "text", "label": "Witness Signature", "required": true},
      "disposalNotes": {"type": "textarea", "label": "Disposal Notes"}
    },
    "certificateGeneration": {
      "certificateNumber": {"type": "text", "label": "Certificate Number", "generated": true},
      "certificateDate": {"type": "date", "label": "Certificate Date"}
    }
  },
  "systemActions": ["Flag samples approaching retention expiry", "Validate dual authorization", "Generate disposal certificate", "Update sample status: Disposed", "Archive disposal records"],
  "nextPage": "Reporting & Audit"
}

{
  "pageDescription": "Reporting & Audit",
  "dataPoints": {
    "reportGeneration": {
      "reportType": {"type": "choice", "label": "Report Type", "options": ["Inventory Summary", "Temperature Excursion Log", "Sample Transaction History", "Disposal Certificates", "Storage Utilization", "Project Sample Counts", "Retention Expiry Report", "QC Inspection Summary"], "required": true},
      "dateRangeStart": {"type": "date", "label": "Date Range Start"},
      "dateRangeEnd": {"type": "date", "label": "Date Range End"},
      "projectFilter": {"type": "reference", "label": "Filter by Project", "source": "project"},
      "statusFilter": {"type": "multiSelect", "label": "Filter by Status", "options": ["Active", "Quarantine", "Checked Out", "Disposed"]},
      "exportFormat": {"type": "choice", "label": "Export Format", "options": ["CSV", "PDF", "FHIR Bundle"]}
    },
    "auditTrail": {
      "sampleBarcode": {"type": "barcode", "label": "Sample Barcode for Audit"},
      "auditDateRange": {"type": "dateRange", "label": "Audit Date Range"},
      "actionTypeFilter": {"type": "multiSelect", "label": "Filter by Action Type", "options": ["Registration", "Storage", "Retrieval", "QC Inspection", "Status Change", "Disposal"]}
    },
    "complianceDocumentation": {
      "complianceType": {"type": "choice", "label": "Compliance Documentation Type", "options": ["ISO 20387:2018 Checklist", "Annual Review Report", "Accreditation Evidence Pack"]},
      "generatedDate": {"type": "date", "label": "Generated Date"},
      "generatedBy": {"type": "text", "label": "Generated By"}
    }
  },
  "systemActions": ["Generate selected reports", "Retrieve audit trail", "Export in selected format", "Generate compliance documentation"]
}
